#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long maxAns = -9223372036854775807LL-1;
        long long maxEnding = 0, minEnding = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld",&x);
            if(i==0){
                maxEnding = minEnding = x;
                maxAns = x;
                continue;
            }
            long long a = x;
            long long b = maxEnding * x;
            long long c = minEnding * x;
            long long newMax = a; if(b>newMax) newMax=b; if(c>newMax) newMax=c;
            long long newMin = a; if(b<newMin) newMin=b; if(c<newMin) newMin=c;
            maxEnding = newMax;
            minEnding = newMin;
            if(maxEnding > maxAns) maxAns = maxEnding;
        }
        printf("%lld\n", maxAns);
    }
    return 0;
}

