import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            st = new StringTokenizer(br.readLine());
            long maxAns = Long.MIN_VALUE;
            long maxEnding = 0, minEnding = 0;
            for (int i = 0; i < N; i++) {
                long x = Long.parseLong(st.nextToken());
                if (i == 0) {
                    maxEnding = minEnding = x;
                    maxAns = x;
                    continue;
                }
                long a = x;
                long b = maxEnding * x;
                long c = minEnding * x;
                long newMax = Math.max(a, Math.max(b, c));
                long newMin = Math.min(a, Math.min(b, c));
                maxEnding = newMax;
                minEnding = newMin;
                if (maxEnding > maxAns) maxAns = maxEnding;
            }
            sb.append(maxAns).append('\n');
        }
        System.out.print(sb.toString());
    }
}

